joi_block.script:
t1 = (#TemperatureSensor #Kitchen).temperatureSensor_temperature
delay(15 MIN)
t2 = (#TemperatureSensor #Kitchen).temperatureSensor_temperature
diff = t2 - t1
if (diff < 0) {
diff = t1 - t2
}
if (diff >= 5) {
(#Plug #Switch #Kitchen #Fan).switch_on()
}

